WIDTH, HEIGHT = 100, 100

class Dot:
    def __init__(self, x, y, vx, vy):
        self.x, self.y   = x, y
        self.vx, self.vy = vx, vy

    def move(self):
        self.x += self.vx
        self.y += self.vy
        # Bounce!
        if self.x < 0 or self.x > WIDTH:
            self.vx *= -1
        if self.y < 0 or self.y > HEIGHT:
            self.vy *= -1

d = Dot(95, 50, 3, 2)
for step in range(10):
    d.move()
    print(f'Step {step+1}: ({d.x:.0f}, {d.y:.0f})  vel=({d.vx}, {d.vy})')

import numpy as np

class Boid:
    def __init__(self, x, y, vx, vy):
        self.pos = np.array([x, y], dtype=float)
        self.vel = np.array([vx, vy], dtype=float)

    def move(self, width, height):
        self.pos += self.vel
        # Bounce off walls
        for i, limit in enumerate([width, height]):
            if self.pos[i] < 0:
                self.pos[i] = 0
                self.vel[i] *= -1
            elif self.pos[i] > limit:
                self.pos[i] = limit
                self.vel[i] *= -1

    def speed(self):
        return np.linalg.norm(self.vel)

b = Boid(50, 50, 2, -1)
for _ in range(5):
    b.move(100, 100)
    print(f'pos=({b.pos[0]:.0f},{b.pos[1]:.0f})  speed={b.speed():.1f}')

def separation(boid, neighbours, min_dist=15):
    steer = np.array([0.0, 0.0])
    for other in neighbours:
        diff = boid.pos - other.pos
        dist = np.linalg.norm(diff)
        if dist < min_dist and dist > 0:
            steer += diff / dist  # push away
    return steer

