import numpy as np

class Boid:
    def __init__(self, x, y, vx, vy):
        self.pos = np.array([x, y], dtype=float)
        self.vel = np.array([vx, vy], dtype=float)

    def move(self, w, h):
        self.pos += self.vel
        for i, limit in enumerate([w, h]):
            if self.pos[i] < 0:
                self.pos[i] = 0; self.vel[i] *= -1
            elif self.pos[i] > limit:
                self.pos[i] = limit; self.vel[i] *= -1

class Predator(Boid):
    def __init__(self, x, y, vx, vy):
        super().__init__(x, y, vx, vy)
        self.is_predator = True

    def chase(self, target):
        direction = target.pos - self.pos
        dist = np.linalg.norm(direction)
        if dist > 0:
            self.vel += 0.05 * direction / dist

p = Predator(10, 10, 1, 1)
prey = Boid(80, 80, 0, 0)
print(f'Predator at {p.pos}, prey at {prey.pos}')
for _ in range(20):
    p.chase(prey)
    p.move(100, 100)
print(f'Predator at ({p.pos[0]:.0f}, {p.pos[1]:.0f}) — getting closer!')

def get_neighbours(boid, flock, radius):
    return [b for b in flock if b is not boid
            and np.linalg.norm(b.pos - boid.pos) < radius]

def separation(boid, neighbours, min_dist=15):
    steer = np.array([0.0, 0.0])
    for n in neighbours:
        diff = boid.pos - n.pos
        d = np.linalg.norm(diff)
        if 0 < d < min_dist:
            steer += diff / d
    return steer

def alignment(boid, neighbours):
    if not neighbours: return np.array([0.0, 0.0])
    return np.mean([b.vel for b in neighbours], axis=0) - boid.vel

def cohesion(boid, neighbours):
    if not neighbours: return np.array([0.0, 0.0])
    return np.mean([b.pos for b in neighbours], axis=0) - boid.pos

def flee(boid, predator, radius=30):
    diff = boid.pos - predator.pos
    d = np.linalg.norm(diff)
    if 0 < d < radius:
        return 3.0 * diff / d
    return np.array([0.0, 0.0])

print('✅ Flocking rules defined')
